import NextAuth, { NextAuthOptions } from "next-auth";
import GoogleProvider from "next-auth/providers/google";
import FacebookProvider from "next-auth/providers/facebook";
import CredentialsProvider from "next-auth/providers/credentials";
import bcrypt from "bcryptjs";
import dbConnect from "@/lib/mongodb";
import User from "@/models/User";

export const authOptions: NextAuthOptions = {
    providers: [
        GoogleProvider({
            clientId: process.env.GOOGLE_CLIENT_ID as string,
            clientSecret: process.env.GOOGLE_CLIENT_SECRET as string,
        }),
        FacebookProvider({
            clientId: process.env.FACEBOOK_CLIENT_ID as string,
            clientSecret: process.env.FACEBOOK_CLIENT_SECRET as string,
        }),
        CredentialsProvider({
            name: "Email and Password",
            credentials: {
                email: { label: "Email", type: "email" },
                password: { label: "Password", type: "password" },
            },
            async authorize(credentials) {
                if (!credentials?.email || !credentials?.password) {
                    throw new Error("Missing credentials");
                }

                await dbConnect();
                const user = await User.findOne({ email: credentials.email });

                if (!user || !user.password) {
                    throw new Error("No user found with this email");
                }

                const isPasswordValid = await bcrypt.compare(
                    credentials.password,
                    user.password
                );

                if (!isPasswordValid) {
                    throw new Error("Invalid password");
                }

                return {
                    id: user._id.toString(),
                    name: user.name,
                    email: user.email,
                    image: user.image,
                    rank: user.rank,
                    xp: user.xp,
                };
            },
        }),
    ],
    callbacks: {
        async signIn({ user, account, profile }) {
            if (account?.provider === "google" || account?.provider === "facebook") {
                await dbConnect();
                let dbUser = await User.findOne({ email: user.email });

                if (!dbUser) {
                    dbUser = await User.create({
                        name: user.name,
                        email: user.email,
                        image: user.image,
                    });
                }
                user.id = dbUser._id.toString();
                // @ts-ignore - custom properties
                user.rank = dbUser.rank;
                // @ts-ignore
                user.xp = dbUser.xp;
            }
            return true;
        },
        async jwt({ token, user, trigger, session }) {
            // User is passed in on initial sign in
            if (user) {
                token.id = user.id;
                // @ts-ignore
                token.rank = user.rank;
                // @ts-ignore
                token.xp = user.xp;
            }

            // Allow manually updating token from client side
            if (trigger === "update" && session) {
                token.rank = session.rank;
                token.xp = session.xp;
            }

            return token;
        },
        async session({ session, token }) {
            if (token && session.user) {
                // @ts-ignore
                session.user.id = token.id;
                // @ts-ignore
                session.user.rank = token.rank;
                // @ts-ignore
                session.user.xp = token.xp;
            }
            return session;
        },
    },
    pages: {
        signIn: "/auth/signin", // Custom sign-in page we will build later
    },
    session: {
        strategy: "jwt",
    },
    secret: process.env.NEXTAUTH_SECRET,
};

const handler = NextAuth(authOptions);

export { handler as GET, handler as POST };

import { NextResponse } from "next/server";
import nodemailer from "nodemailer";

export async function POST(req: Request) {
    try {
        const { name, email, message } = await req.json();

        if (!name || !email || !message) {
            return NextResponse.json(
                { error: "Name, email, and message are required" },
                { status: 400 }
            );
        }

        // Configure your actual SMTP credentials in .env.local
        const transporter = nodemailer.createTransport({
            host: process.env.SMTP_HOST || "smtp.example.com",
            port: Number(process.env.SMTP_PORT) || 587,
            secure: process.env.SMTP_SECURE === "true", // true for 465, false for other ports
            auth: {
                user: process.env.SMTP_USER,
                pass: process.env.SMTP_PASS,
            },
        });

        const mailOptions = {
            from: `"${name}" <${email}>`, // Sender address
            to: process.env.ADMIN_EMAIL || "admin@rankup.com", // List of receivers
            subject: `New Contact Form Submission from ${name}`, // Subject line
            text: `You have received a new message from ${name} (${email}):\n\n${message}`, // Plain text body
            html: `<p>You have received a new message from <strong>${name}</strong> (${email}):</p><p>${message}</p>`, // HTML body
        };

        await transporter.sendMail(mailOptions);

        return NextResponse.json({ success: true });
    } catch (error: any) {
        console.error("Error sending email:", error);
        // If SMTP is not configured, we still want to gracefully fail for the demo
        return NextResponse.json(
            { error: "Failed to send email. Check SMTP configuration." },
            { status: 500 }
        );
    }
}

import { NextResponse } from "next/server";
import { getServerSession } from "next-auth";
import OpenAI from "openai";
import { authOptions } from "@/app/api/auth/[...nextauth]/route";

const openai = new OpenAI({
    apiKey: process.env.OPENAI_API_KEY,
});

export async function POST(req: Request) {
    try {
        const session = await getServerSession(authOptions);

        if (!session) {
            //      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }

        const { difficulty } = await req.json();

        if (!difficulty || difficulty < 1 || difficulty > 10) {
            return NextResponse.json(
                { error: "Invalid difficulty level (must be 1-10)" },
                { status: 400 }
            );
        }

        const completion = await openai.chat.completions.create({
            model: "gpt-4o-mini", // or the required model
            messages: [
                {
                    role: "system",
                    content: `You are a strict, highly intelligent quiz master generating multiple-choice questions for a competitive gamified platform. 
          The user is currently at difficulty level ${difficulty} out of 10. 
          Generate a question appropriate for this difficulty. 
          Level 1 should be fundamental general knowledge. Level 10 should be highly specific, expert-level trivia or complex problem-solving.
          
          Respond ONLY with a valid JSON object matching this schema:
          {
            "question": "The question text",
            "options": ["Option A", "Option B", "Option C", "Option D"],
            "correctAnswerIndex": <0-3>,
            "explanation": "Brief explanation of why the answer is correct."
          }`,
                },
            ],
            response_format: { type: "json_object" },
        });

        const resultText = completion.choices[0].message.content;
        if (!resultText) throw new Error("No response from OpenAI");

        const questionData = JSON.parse(resultText);

        return NextResponse.json(questionData);
    } catch (error: any) {
        console.error("Error generating question:", error);
        return NextResponse.json(
            { error: "Failed to generate question" },
            { status: 500 }
        );
    }
}

import { NextResponse } from "next/server";
import { getServerSession } from "next-auth";
import { authOptions } from "@/app/api/auth/[...nextauth]/route";
import dbConnect from "@/lib/mongodb";
import User from "@/models/User";

const RANKS = [
    { name: "Bronze", min: 0 },
    { name: "Silver", min: 1000 },
    { name: "Gold", min: 3000 },
    { name: "Platinum", min: 5000 },
    { name: "Diamond", min: 7000 },
    { name: "Master", min: 8500 },
    { name: "Grandmaster", min: 9500 },
];

function calculateRank(xp: number): string {
    let currentRank = "Bronze";
    for (const rank of RANKS) {
        if (xp >= rank.min) {
            currentRank = rank.name;
        }
    }
    return currentRank;
}

export async function POST(req: Request) {
    try {
        const session = await getServerSession(authOptions);

        if (!session || !session.user) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }

        const { xpChange, isCorrect, difficulty } = await req.json();

        if (typeof xpChange !== "number") {
            return NextResponse.json({ error: "Invalid payload" }, { status: 400 });
        }

        await dbConnect();

        // @ts-ignore
        const userId = session.user.id;
        const user = await User.findById(userId);

        if (!user) {
            return NextResponse.json({ error: "User not found" }, { status: 404 });
        }

        // Update XP (ensure it doesn't go below 0)
        user.xp = Math.max(0, user.xp + xpChange);
        user.matchesPlayed += 1;

        // Recalculate Rank
        const newRank = calculateRank(user.xp);
        const rankChanged = user.rank !== newRank;

        user.rank = newRank;

        await user.save();

        return NextResponse.json({
            success: true,
            newXp: user.xp,
            newRank: user.rank,
            rankChanged,
        });
    } catch (error: any) {
        console.error("Error submitting test result:", error);
        return NextResponse.json(
            { error: "Internal server error" },
            { status: 500 }
        );
    }
}

"use client";

import { signIn } from "next-auth/react";
import { useState } from "react";
import { BoltIcon } from "@/app/icons";

export default function SignInPage() {
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [error, setError] = useState("");
    const [loading, setLoading] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError("");

        const res = await signIn("credentials", {
            email,
            password,
            redirect: true,
            callbackUrl: "/",
        });

        if (res?.error) {
            setError(res.error);
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center p-6 pb-32">
            <div className="glass-card w-full max-w-md p-8 rounded-3xl relative overflow-hidden shadow-2xl">
                <div className="absolute top-0 right-0 w-64 h-64 bg-primary/20 rounded-full blur-[80px] pointer-events-none -z-10" />

                <div className="text-center mb-10">
                    <BoltIcon className="h-10 w-10 text-primary mx-auto mb-4" />
                    <h1 className="text-3xl font-black">Welcome Back</h1>
                    <p className="text-base-content/60 mt-2">Sign in to continue testing.</p>
                </div>

                <div className="flex flex-col gap-4 mb-6">
                    <button
                        onClick={() => signIn("google", { callbackUrl: "/" })}
                        className="btn btn-outline"
                    >
                        <svg className="w-5 h-5" viewBox="0 0 24 24">
                            <path
                                fill="currentColor"
                                d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"
                            />
                            <path
                                fill="currentColor"
                                d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"
                            />
                            <path
                                fill="currentColor"
                                d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"
                            />
                            <path
                                fill="currentColor"
                                d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"
                            />
                        </svg>
                        Continue with Google
                    </button>

                    <button
                        onClick={() => signIn("facebook", { callbackUrl: "/" })}
                        className="btn bg-[#1877F2] text-white hover:bg-[#1877F2]/90 border-none"
                    >
                        <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24">
                            <path d="M24 12.073c0-6.627-5.373-12-12-12s-12 5.373-12 12c0 5.99 4.388 10.954 10.125 11.854v-8.385H7.078v-3.469h3.047V9.43c0-3.007 1.792-4.669 4.533-4.669 1.312 0 2.686.235 2.686.235v2.953H15.83c-1.491 0-1.956.925-1.956 1.874v2.25h3.328l-.532 3.469h-2.796v8.385C19.612 23.027 24 18.062 24 12.073z" />
                        </svg>
                        Continue with Facebook
                    </button>
                </div>

                <div className="divider text-base-content/40 text-sm">OR</div>

                <form onSubmit={handleSubmit} className="flex flex-col gap-5 mt-6">
                    <div className="form-control">
                        <input
                            type="email"
                            placeholder="Email address"
                            className="input input-bordered w-full bg-base-200/50"
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            required
                        />
                    </div>
                    <div className="form-control">
                        <input
                            type="password"
                            placeholder="Password"
                            className="input input-bordered w-full bg-base-200/50"
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            required
                        />
                    </div>

                    {error && <div className="text-error text-sm font-bold text-center mt-2">{error}</div>}

                    <button type="submit" disabled={loading} className="btn btn-primary mt-2">
                        {loading ? <span className="loading loading-spinner"></span> : "Sign In with Email"}
                    </button>
                </form>

                <p className="text-center text-sm text-base-content/60 mt-8">
                    Don't have an account?{" "}
                    <span className="text-primary font-bold cursor-pointer hover:underline">
                        Sign up (Demo)
                    </span>
                </p>
            </div>
        </div>
    );
}

"use client";

import { useState } from "react";
import { SparklesIcon } from "@/app/icons";

export default function ContactPage() {
    const [loading, setLoading] = useState(false);
    const [success, setSuccess] = useState(false);
    const [error, setError] = useState("");

    const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        setLoading(true);
        setError("");
        setSuccess(false);

        const formData = new FormData(e.currentTarget);
        const data = {
            name: formData.get("name"),
            email: formData.get("email"),
            message: formData.get("message"),
        };

        try {
            const res = await fetch("/api/contact", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(data),
            });

            if (res.ok) {
                setSuccess(true);
                (e.target as HTMLFormElement).reset();
            } else {
                const errData = await res.json();
                setError(errData.error || "Failed to send message");
            }
        } catch (err) {
            setError("An unexpected error occurred");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen py-20 px-6 max-w-3xl mx-auto">
            <div className="text-center mb-12">
                <SparklesIcon className="h-10 w-10 text-primary mx-auto mb-4" />
                <h1 className="text-4xl md:text-5xl font-black mb-4">Contact Us</h1>
                <p className="text-base-content/60 text-lg">
                    Have a question or feedback? We'd love to hear from you.
                </p>
            </div>

            <div className="glass-card p-8 md:p-12 rounded-3xl shadow-xl">
                <form onSubmit={handleSubmit} className="flex flex-col gap-6">
                    <div className="form-control">
                        <label className="label">
                            <span className="label-text font-bold">Your Name</span>
                        </label>
                        <input
                            type="text"
                            name="name"
                            required
                            placeholder="John Doe"
                            className="input input-bordered w-full bg-base-200/50"
                        />
                    </div>

                    <div className="form-control">
                        <label className="label">
                            <span className="label-text font-bold">Your Email</span>
                        </label>
                        <input
                            type="email"
                            name="email"
                            required
                            placeholder="john@example.com"
                            className="input input-bordered w-full bg-base-200/50"
                        />
                    </div>

                    <div className="form-control">
                        <label className="label">
                            <span className="label-text font-bold">Message</span>
                        </label>
                        <textarea
                            name="message"
                            required
                            placeholder="How can we help you?"
                            className="textarea textarea-bordered h-32 bg-base-200/50"
                        ></textarea>
                    </div>

                    {error && <div className="text-error text-sm font-bold">{error}</div>}
                    {success && (
                        <div className="text-success text-sm font-bold">
                            Message sent successfully! We'll get back to you soon.
                        </div>
                    )}

                    <button
                        type="submit"
                        disabled={loading}
                        className="btn btn-primary mt-4"
                    >
                        {loading ? (
                            <span className="loading loading-spinner"></span>
                        ) : (
                            "Send Message"
                        )}
                    </button>
                </form>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import { motion, AnimatePresence } from "framer-motion";

type Question = {
    question: string;
    options: string[];
    correctAnswerIndex: number;
    explanation: string;
};

export default function TestPage() {
    const { data: session, status } = useSession();
    const router = useRouter();

    const [loading, setLoading] = useState(false);
    const [question, setQuestion] = useState<Question | null>(null);
    const [difficulty, setDifficulty] = useState(1);
    const [score, setScore] = useState(0);
    const [streak, setStreak] = useState(0);
    const [timeLeft, setTimeLeft] = useState(60);
    const [isTestActive, setIsTestActive] = useState(false);
    const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null);
    const [feedback, setFeedback] = useState<"correct" | "incorrect" | null>(null);

    useEffect(() => {
        if (status === "unauthenticated") {
            router.push("/api/auth/signin");
        }
    }, [status, router]);

    useEffect(() => {
        let timer: NodeJS.Timeout;
        if (isTestActive && timeLeft > 0 && !feedback) {
            timer = setInterval(() => setTimeLeft((prev) => prev - 1), 1000);
        } else if (timeLeft === 0 && isTestActive) {
            endTest();
        }
        return () => clearInterval(timer);
    }, [isTestActive, timeLeft, feedback]);

    const fetchQuestion = async (currentDifficulty: number) => {
        setLoading(true);
        setSelectedAnswer(null);
        setFeedback(null);
        try {
            const res = await fetch("/api/questions", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ difficulty: currentDifficulty }),
            });
            const data = await res.json();
            if (res.ok) setQuestion(data);
            else console.error(data.error);
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    const startTest = () => {
        setIsTestActive(true);
        setScore(0);
        setDifficulty(1);
        setTimeLeft(60);
        setStreak(0);
        fetchQuestion(1);
    };

    const endTest = async () => {
        setIsTestActive(false);
        setQuestion(null);

        // Submit score
        if (score > 0) {
            try {
                await fetch("/api/test/submit", {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({ xpChange: score }),
                });
            } catch (e) {
                console.error("Failed to submit score", e);
            }
        }
    };

    const handleAnswerClick = (index: number) => {
        if (selectedAnswer !== null || !question) return;

        setSelectedAnswer(index);
        const isCorrect = index === question.correctAnswerIndex;

        if (isCorrect) {
            setFeedback("correct");
            const pointsEarned = 10 * difficulty * (1 + streak * 0.1);
            setScore((prev) => prev + Math.round(pointsEarned));
            setStreak((prev) => prev + 1);
            setDifficulty((prev) => Math.min(10, prev + 1));

            setTimeout(() => fetchQuestion(Math.min(10, difficulty + 1)), 2000);
        } else {
            setFeedback("incorrect");
            const pointsLost = 5 * difficulty; // penalty
            setScore((prev) => Math.max(0, prev - pointsLost));
            setStreak(0);
            setDifficulty((prev) => Math.max(1, prev - 1));

            setTimeout(() => fetchQuestion(Math.max(1, difficulty - 1)), 3500);
        }
    };

    if (status === "loading") {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <span className="loading loading-spinner text-primary loading-lg"></span>
            </div>
        );
    }

    return (
        <div className="min-h-screen pt-10 pb-20 px-4 md:px-8 max-w-4xl mx-auto">
            <div className="flex items-center justify-between mb-8 glass-card p-4 rounded-2xl">
                <div className="flex gap-4">
                    <div className="stat-value text-primary">{score} XP</div>
                    {streak >= 3 && (
                        <div className="badge badge-accent animate-pulse badge-lg">
                            ≡ƒöÑ {streak} Streak
                        </div>
                    )}
                </div>
                <div className="flex items-center gap-2">
                    <span className="text-xl font-mono countdown">
                        {/* @ts-ignore - daisyui countdown styling */}
                        <span style={{ "--value": timeLeft }}></span>
                    </span>
                    <span className="text-base-content/50 uppercase text-xs font-bold">
                        Secs Left
                    </span>
                </div>
            </div>

            {!isTestActive ? (
                <div className="text-center mt-20">
                    <h1 className="text-4xl font-black mb-4">Adaptive Knowledge Test</h1>
                    <p className="text-base-content/60 max-w-lg mx-auto mb-8">
                        Answer rapidly scaling AI-generated questions. Get them right to
                        increase difficulty and earn multipliers. Get them wrong, lose points.
                    </p>
                    <button
                        onClick={startTest}
                        className="btn btn-primary btn-lg pulse-glow"
                    >
                        Start Session (60s)
                    </button>
                </div>
            ) : (
                <div className="relative min-h-[400px]">
                    <AnimatePresence mode="wait">
                        {loading ? (
                            <motion.div
                                key="loading"
                                initial={{ opacity: 0 }}
                                animate={{ opacity: 1 }}
                                exit={{ opacity: 0 }}
                                className="absolute inset-0 flex flex-col items-center justify-center"
                            >
                                <div className="loading loading-bars loading-md text-primary mb-2"></div>
                                <p className="text-sm text-base-content/50 animate-pulse">
                                    Generating Lvl {difficulty} Question...
                                </p>
                            </motion.div>
                        ) : question ? (
                            <motion.div
                                key={question.question}
                                initial={{ opacity: 0, y: 20 }}
                                animate={{ opacity: 1, y: 0 }}
                                exit={{ opacity: 0, x: -20 }}
                                transition={{ duration: 0.3 }}
                                className="glass-card p-6 md:p-10 rounded-3xl"
                            >
                                <div className="flex justify-between items-center mb-6">
                                    <span className="badge badge-outline">Lvl {difficulty}</span>
                                </div>

                                <h2 className="text-2xl md:text-3xl font-bold mb-8 leading-tight">
                                    {question.question}
                                </h2>

                                <div className="space-y-3">
                                    {question.options.map((opt, idx) => {
                                        let btnClass = "btn btn-outline btn-lg w-full justify-start h-auto py-4 font-normal text-left";
                                        if (selectedAnswer !== null) {
                                            if (idx === question.correctAnswerIndex) {
                                                btnClass = "btn btn-success btn-lg w-full justify-start h-auto py-4 text-left pointer-events-none";
                                            } else if (idx === selectedAnswer) {
                                                btnClass = "btn btn-error btn-lg w-full justify-start h-auto py-4 text-left pointer-events-none";
                                            } else {
                                                btnClass = "btn btn-outline btn-lg w-full justify-start h-auto py-4 opacity-50 pointer-events-none text-left";
                                            }
                                        }

                                        return (
                                            <button
                                                key={idx}
                                                onClick={() => handleAnswerClick(idx)}
                                                className={btnClass}
                                                disabled={selectedAnswer !== null}
                                            >
                                                <span className="mr-3 font-mono opacity-50">
                                                    {String.fromCharCode(65 + idx)}
                                                </span>
                                                {opt}
                                            </button>
                                        );
                                    })}
                                </div>

                                {feedback && (
                                    <motion.div
                                        initial={{ opacity: 0, y: 10 }}
                                        animate={{ opacity: 1, y: 0 }}
                                        className={`mt-6 p-4 rounded-xl text-sm ${feedback === "correct"
                                                ? "bg-success/10 text-success"
                                                : "bg-error/10 text-error"
                                            }`}
                                    >
                                        <p className="font-bold mb-1">
                                            {feedback === "correct" ? "Correct!" : "Incorrect."}
                                        </p>
                                        <p>{question.explanation}</p>
                                    </motion.div>
                                )}
                            </motion.div>
                        ) : null}
                    </AnimatePresence>
                </div>
            )}
        </div>
    );
}

import mongoose from "mongoose";

const MONGODB_URI = process.env.MONGODB_URI;

if (!MONGODB_URI) {
    throw new Error(
        "Please define the MONGODB_URI environment variable inside .env.local"
    );
}

/**
 * Global is used here to maintain a cached connection across hot reloads
 * in development. This prevents connections growing exponentially
 * during API Route usage.
 */
// @ts-ignore
let cached = global.mongoose;

if (!cached) {
    // @ts-ignore
    cached = global.mongoose = { conn: null, promise: null };
}

async function dbConnect() {
    if (cached.conn) {
        return cached.conn;
    }

    if (!cached.promise) {
        const opts = {
            bufferCommands: false,
        };

        cached.promise = mongoose.connect(MONGODB_URI as string, opts).then((mongoose) => {
            return mongoose;
        });
    }
    cached.conn = await cached.promise;
    return cached.conn;
}

export default dbConnect;
